import React, { useState } from 'react';
import quizTopics from './quizTopics';
import QuizBuilder, { fetchQuiz } from './QuizBuilder';

function PredefinedQuizList() {
  const [selectedTopic, setSelectedTopic] = useState(null);
  const [quiz, setQuiz] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // When a topic is selected, fetch/generate a quiz for that topic
  const handleTopicSelect = async (topic) => {
    setSelectedTopic(topic);
    setLoading(true);
    setError(null);
    setQuiz(null);
    try {
      const data = await fetchQuiz({ prompt: topic.title, role: topic.role, difficulty: topic.difficulty, num_questions: 10, explanations: true });
      setQuiz({ ...data, topic });
    } catch (err) {
      setError(err.message || 'Failed to generate quiz.');
    } finally {
      setLoading(false);
    }
  };

  const handleRestart = () => {
    setQuiz(null);
    setSelectedTopic(null);
    setError(null);
  };

  if (loading) return <div style={{textAlign:'center',marginTop:'2rem'}}>Generating quiz...</div>;
  if (error) return <div style={{color:'red',textAlign:'center',marginTop:'2rem'}}>{error}</div>;

  if (quiz && selectedTopic) {
    return (
      <div style={{maxWidth: 700, margin: '0 auto'}}>
        <button onClick={handleRestart} style={{marginBottom: 16, background: 'none', border: 'none', color: '#007bff', cursor: 'pointer'}}>← Back to topics</button>
        <QuizBuilder quiz={quiz} topic={selectedTopic} onRestart={handleRestart} />
      </div>
    );
  }

  // Topic grid
  return (
    <div style={{display: 'flex', flexWrap: 'wrap', gap: 32, justifyContent: 'center', marginTop: 32}}>
      {quizTopics.map(topic => (
        <div key={topic.key} style={{width: 260, background: '#fff', borderRadius: 12, boxShadow: '0 2px 16px #0001', padding: 20, cursor: 'pointer', display: 'flex', flexDirection: 'column', alignItems: 'center'}} onClick={() => handleTopicSelect(topic)}>
          <img src={topic.image} alt={topic.title} style={{width: '100%', borderRadius: 10, maxHeight: 120, objectFit: 'cover', marginBottom: 12}} />
          <div style={{fontWeight: 700, fontSize: 18, marginBottom: 6, textAlign: 'center'}}>{topic.title}</div>
          <div style={{fontSize: 12, color: '#888', marginBottom: 6, textAlign: 'center'}}>Image: {topic.imageAttribution}</div>
        </div>
      ))}
    </div>
  );
}

export default PredefinedQuizList;
